import { useState } from "react";
import Swal from "sweetalert2";
import {
  auth,
  db,
  createUserWithEmailAndPassword,
  collection,
  query,
  where,
  getDocs,
  setDoc,
  doc,
} from "../firebase";
import { useNavigate } from "react-router-dom";

// 🔹 Função de validação de CPF
function validarCPF(cpf) {
  cpf = cpf.replace(/[^\d]+/g, "");
  if (cpf.length !== 11 || /^(\d)\1+$/.test(cpf)) return false;

  let soma = 0;
  for (let i = 0; i < 9; i++) soma += parseInt(cpf.charAt(i)) * (10 - i);
  let resto = (soma * 10) % 11;
  if (resto === 10 || resto === 11) resto = 0;
  if (resto !== parseInt(cpf.charAt(9))) return false;

  soma = 0;
  for (let i = 0; i < 10; i++) soma += parseInt(cpf.charAt(i)) * (11 - i);
  resto = (soma * 10) % 11;
  if (resto === 10 || resto === 11) resto = 0;
  return resto === parseInt(cpf.charAt(10));
}

export default function Cadastro() {
  const [email, setEmail] = useState("");
  const [cpf, setCpf] = useState("");
  const [senha, setSenha] = useState("");
  const [bloco, setBloco] = useState("");
  const [apartamento, setApartamento] = useState("");
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleCadastro = async (e) => {
    e.preventDefault();
    if (loading) return;
    setLoading(true);
    console.clear();
    console.log("🚀 Iniciando cadastro...");

    try {
      // 1️⃣ Valida CPF
      if (!validarCPF(cpf)) {
        await Swal.fire({
          icon: "error",
          title: "CPF inválido",
          text: "Digite um CPF válido antes de continuar.",
          confirmButtonColor: "#4f46e5",
        });
        return;
      }

      console.log("✅ CPF válido, verificando duplicidade...");

      // 2️⃣ Verifica duplicidade
      const q = query(collection(db, "usuarios"), where("cpf", "==", cpf));
      const snap = await getDocs(q);

      if (!snap.empty) {
        console.warn("⚠️ CPF já cadastrado!");
        await Swal.fire({
          icon: "warning",
          title: "CPF já cadastrado",
          text: "Entre em contato com a Síndica para ativação da conta.",
          confirmButtonColor: "#4f46e5",
        });
        return;
      }

      console.log("🧩 Criando usuário no Firebase Auth...");

      // 3️⃣ Cria usuário
      const cred = await createUserWithEmailAndPassword(auth, email, senha);
      const user = cred.user;

      console.log("✅ Usuário criado:", user.uid);

      // 4️⃣ Cria no Firestore
      await setDoc(doc(db, "usuarios", user.uid), {
        email,
        cpf,
        bloco,
        apartamento,
        ativo: false,
        role: "morador",
        criadoEm: new Date(),
      });

      console.log("✅ Gravado usuário no Firestore.");

      // 5️⃣ Popup de sucesso
      await Swal.fire({
        icon: "success",
        title: "Cadastro realizado!",
        html: `
          <p>Seu cadastro foi criado com sucesso 🎉</p>
          <p class="text-gray-500 mt-1">Aguarde a aprovação do administrador.</p>
        `,
        confirmButtonText: "Voltar ao Login",
        confirmButtonColor: "#4f46e5",
      });

      navigate("/");
    } catch (error) {
      console.error("❌ Erro ao cadastrar:", error);

      await Swal.fire({
        icon: "error",
        title: "Erro no cadastro",
        text: error.message || "Verifique os dados e tente novamente.",
        confirmButtonColor: "#4f46e5",
      });
    } finally {
      console.log("✅ Finalizando processo (setLoading false).");
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-blue-100 via-blue-50 to-indigo-100 p-4">
      <div className="w-full max-w-md bg-white/50 backdrop-blur-lg shadow-lg border border-white/30 rounded-3xl p-8 md:p-10">
        <h1 className="text-3xl font-bold text-center text-gray-800 mb-2">
          Cadastrar-se<span className="text-indigo-500">.</span>
        </h1>
        <p className="text-center text-gray-600 mb-8 text-sm">
          Preencha os dados para criar sua conta
        </p>

        <form onSubmit={handleCadastro} className="flex flex-col gap-5">
          <input
            type="email"
            placeholder="E-mail"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            required
            className="w-full p-4 rounded-xl border border-gray-300 focus:border-indigo-400 focus:ring-2 focus:ring-indigo-200 outline-none transition text-gray-800 placeholder-gray-400"
          />
          <input
            type="text"
            placeholder="CPF (somente números)"
            value={cpf}
            onChange={(e) => setCpf(e.target.value)}
            required
            maxLength={14}
            className="w-full p-4 rounded-xl border border-gray-300 focus:border-indigo-400 focus:ring-2 focus:ring-indigo-200 outline-none transition text-gray-800 placeholder-gray-400"
          />
          <input
            type="password"
            placeholder="Senha"
            value={senha}
            onChange={(e) => setSenha(e.target.value)}
            required
            minLength={6}
            className="w-full p-4 rounded-xl border border-gray-300 focus:border-indigo-400 focus:ring-2 focus:ring-indigo-200 outline-none transition text-gray-800 placeholder-gray-400"
          />
          <div className="flex gap-3">
            <input
              type="text"
              placeholder="Bloco"
              value={bloco}
              onChange={(e) => setBloco(e.target.value)}
              required
              className="w-1/2 p-4 rounded-xl border border-gray-300 focus:border-indigo-400 focus:ring-2 focus:ring-indigo-200 outline-none transition text-gray-800 placeholder-gray-400"
            />
            <input
              type="text"
              placeholder="Apartamento"
              value={apartamento}
              onChange={(e) => setApartamento(e.target.value)}
              required
              className="w-1/2 p-4 rounded-xl border border-gray-300 focus:border-indigo-400 focus:ring-2 focus:ring-indigo-200 outline-none transition text-gray-800 placeholder-gray-400"
            />
          </div>

          <button
            type="submit"
            disabled={loading}
            className={`w-full mt-2 py-4 rounded-xl text-white font-semibold text-lg shadow-md transition-transform transform hover:scale-[1.02] ${
              loading
                ? "bg-indigo-300 cursor-not-allowed"
                : "bg-gradient-to-r from-sky-500 to-indigo-500 hover:opacity-90"
            }`}
          >
            {loading ? (
              <div className="flex items-center justify-center gap-2">
                <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                Enviando...
              </div>
            ) : (
              "Cadastrar"
            )}
          </button>

          <p
            onClick={() => navigate("/")}
            className="text-center text-sm text-indigo-600 hover:text-indigo-700 mt-3 cursor-pointer"
          >
            Já possui uma conta? Faça login
          </p>
        </form>
      </div>
    </div>
  );
}
